import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { ApiService } from './api.service';
import { PagedResult } from '../models/common.models';
import { OrgListDto, OrgDetailDto, CreateOrgDto, UpdateOrgDto } from '../models/organization.models';

@Injectable({ providedIn: 'root' })
export class OrganizationService {
  constructor(private api: ApiService) {}

  getAll(page = 1, pageSize = 20): Observable<PagedResult<OrgListDto>> {
    return this.api.getPaged<OrgListDto>('organizations', { page, pageSize });
  }

  getById(id: number): Observable<OrgDetailDto> {
    return this.api.get<OrgDetailDto>(`organizations/${id}`);
  }

  create(dto: CreateOrgDto): Observable<OrgDetailDto> {
    return this.api.post<OrgDetailDto>('organizations', dto);
  }

  update(id: number, dto: UpdateOrgDto): Observable<OrgDetailDto> {
    return this.api.put<OrgDetailDto>(`organizations/${id}`, dto);
  }

  delete(id: number): Observable<void> {
    return this.api.delete(`organizations/${id}`);
  }

  enrollInCourse(orgId: number, courseId: number): Observable<void> {
    return this.api.post<void>(`organizations/${orgId}/enroll/${courseId}`, {});
  }
}
